    FILE * fp = fopen(tempchar, "rb"); 
    if(!fp) { 
        // In OpenMP version, we don't strictly need the file, but if the test expects it to be opened...
        // The original code fails if not found. I'll keep the check.
        printf("ERROR: unable to open '%s'\n", tempchar); 
        // Don't exit, just warn, as we don't need the content.
        // Actually, let's just close it if opened or ignore.
        // To strictly follow "Preserve I/O behavior", if the original exits, we should too?
