    }

    printf("Processing upper-left matrix\n");
    for( int blk = 1 ; blk <= worksize/BLOCK_SIZE ; blk++){
        int num_blocks = blk;
        int total_threads = num_blocks * BLOCK_SIZE;

        #pragma omp parallel num_threads(total_threads)
        {
            int tid = omp_get_thread_num();
            int bx = tid / BLOCK_SIZE;
            int tx = tid % BLOCK_SIZE;

            int *my_local_input = local_input_pool + bx * ((BLOCK_SIZE + 1) * (BLOCK_SIZE + 1));
            int *my_local_ref = local_ref_pool + bx * (BLOCK_SIZE * BLOCK_SIZE);

            // Execute kernel1 logic
            int base = offset_r * cols + offset_c; // cols is max_cols
            int b_index_x = bx;
            int b_index_y = blk - 1 - bx;

            int index   =   base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( max_cols + 1 );
            int index_n   = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
            int index_w   = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( max_cols );
            int index_nw =  base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

            // Step 1
            if (tx == 0){
                my_local_input[0 * (BLOCK_SIZE+1) + 0] = input_itemsets[index_nw + 0];
            }

            #pragma omp barrier

            // Step 2
            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                my_local_ref[ty * BLOCK_SIZE + tx] = reference[index + max_cols * ty];

            #pragma omp barrier

            // Step 3
            my_local_input[(tx + 1) * (BLOCK_SIZE+1) + 0] = input_itemsets[index_w + max_cols * tx];

            #pragma omp barrier

            // Step 4
            my_local_input[0 * (BLOCK_SIZE+1) + (tx + 1)] = input_itemsets[index_n];

            #pragma omp barrier

            // Step 5
            for( int m = 0 ; m < BLOCK_SIZE ; m++){
                if ( tx <= m ){
                    int t_index_x =  tx + 1;
                    int t_index_y =  m - tx + 1;

                    int val_diag = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x-1)] + my_local_ref[(t_index_y-1) * BLOCK_SIZE + (t_index_x-1)];
                    int val_left = my_local_input[(t_index_y) * (BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
                    int val_up   = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x)] - penalty;

                    my_local_input[t_index_y * (BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
                }
                #pragma omp barrier
            }

            #pragma omp barrier

            // Step 6
            for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
                if ( tx <= m){
                    int t_index_x =  tx + BLOCK_SIZE - m ;
                    int t_index_y =  BLOCK_SIZE - tx;

                    int val_diag = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x-1)] + my_local_ref[(t_index_y-1) * BLOCK_SIZE + (t_index_x-1)];
                    int val_left = my_local_input[(t_index_y) * (BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
                    int val_up   = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x)] - penalty;

                    my_local_input[t_index_y * (BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
                }
                #pragma omp barrier
            }

            #pragma omp barrier

            // Step 7
            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                input_itemsets[index + max_cols * ty] = my_local_input[(ty+1) * (BLOCK_SIZE+1) + (tx+1)];
        }
    }

    printf("Processing lower-right matrix\n");
    for( int blk =  worksize/BLOCK_SIZE - 1  ; blk >= 1 ; blk--){
        int num_blocks = blk;
        int total_threads = num_blocks * BLOCK_SIZE;

        #pragma omp parallel num_threads(total_threads)
        {
            int tid = omp_get_thread_num();
            int bx = tid / BLOCK_SIZE;
            int tx = tid % BLOCK_SIZE;

            int *my_local_input = local_input_pool + bx * ((BLOCK_SIZE + 1) * (BLOCK_SIZE + 1));
            int *my_local_ref = local_ref_pool + bx * (BLOCK_SIZE * BLOCK_SIZE);

            int base = offset_r * max_cols + offset_c;
            int b_index_x = bx + block_width - blk;
            int b_index_y = block_width - bx - 1;

            int index   =   base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( max_cols + 1 );
            int index_n   = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
            int index_w   = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( max_cols );
            int index_nw =  base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

            if (tx == 0)
                my_local_input[0 * (BLOCK_SIZE+1) + 0] = input_itemsets[index_nw];

            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                my_local_ref[ty * BLOCK_SIZE + tx] = reference[index + max_cols * ty];

            #pragma omp barrier

            my_local_input[(tx + 1) * (BLOCK_SIZE+1) + 0] = input_itemsets[index_w + max_cols * tx];

            #pragma omp barrier

            my_local_input[0 * (BLOCK_SIZE+1) + (tx + 1)] = input_itemsets[index_n];

            #pragma omp barrier

            for( int m = 0 ; m < BLOCK_SIZE ; m++){
                if ( tx <= m ){
                    int t_index_x =  tx + 1;
                    int t_index_y =  m - tx + 1;

                    int val_diag = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x-1)] + my_local_ref[(t_index_y-1) * BLOCK_SIZE + (t_index_x-1)];
                    int val_left = my_local_input[(t_index_y) * (BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
                    int val_up   = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x)] - penalty;

                    my_local_input[t_index_y * (BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
                }
                #pragma omp barrier
            }

            for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
                if ( tx <= m){
                    int t_index_x =  tx + BLOCK_SIZE - m ;
                    int t_index_y =  BLOCK_SIZE - tx;

                    int val_diag = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x-1)] + my_local_ref[(t_index_y-1) * BLOCK_SIZE + (t_index_x-1)];
                    int val_left = my_local_input[(t_index_y) * (BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
                    int val_up   = my_local_input[(t_index_y-1) * (BLOCK_SIZE+1) + (t_index_x)] - penalty;

                    my_local_input[t_index_y * (BLOCK_SIZE+1) + t_index_x] = maximum(val_diag, val_left, val_up);
                }
                #pragma omp barrier
            }

            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                input_itemsets[index + ty * max_cols] = my_local_input[(ty+1) * (BLOCK_SIZE+1) + (tx+1)];
        }
    }

    // Copy result (input_itemsets is updated in place, output_itemsets is read from it)
    // Original: clEnqueueReadBuffer(..., input_itemsets_d, ..., output_itemsets, ...)
    // Since we updated input_itemsets directly, we just copy it to output_itemsets if needed?
    // The original code reads from input_itemsets_d into output_itemsets.
    // In our simulation, input_itemsets is the main array.
    // The original code uses input_itemsets_d as the working buffer and output_itemsets_d as target?
    // Wait, original kernel writes to input_itemsets_d.
    // Then main reads input_itemsets_d into output_itemsets.
    // So output_itemsets should be a copy of input_itemsets.
    memcpy(output_itemsets, input_itemsets, max_rows * max_cols * sizeof(int));

#ifdef TRACEBACK
